class Solution {
    public int kthFactor(int n, int k) {
        int count = 0;
        for (int i = 1; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                count++;
                if (count == k) {
                    return i;
                }
            }
        }
        int j = (int) Math.sqrt(n);
        for (int i = j; i >= 1; i--) {
            if (n % i == 0 && i * i != n) {
                count++;
                if (count == k) {
                    return n / i;
                }
            }
        }
        return -1;
    }
}
